  const uniqueBadges = Array.from(new Set(computedBadges)).slice(0, 8);
  const aliasDisplay = '@' + String(displayName || 'catador').replace(/^@+/, '').trim().toLowerCase().replace(/\s+/g, '_');
  const verifyBadgeOrBtn = auth.emailVerified
